    if(!arr.length)return "<div class='empty'><div class='empty-icon'>📝</div>还没有阶段总结</div>";

    return arr.slice().reverse().map(function(x){
        return "<div class='sum-card'>"+
            "<div data-lp-summary='"+esc(x.id)+"' data-lp-kind='short'>"+
                "<div class='sum-range'>"+(x.startL||0)+"L - "+(x.endL||0)+"L</div>"+
                "<div class='sum-title'>"+esc(x.title||'阶段总结')+"</div>"+
                "<div class='sum-preview' style='white-space:pre-wrap'>"+esc(x.summary||clip(x.content||'',180))+"</div>"+
                "<div class='sum-meta'>"+
                    "<span class='sum-time'>"+fmt(x.updated_at||x.created_at)+"</span>"+
                    "<span class='sum-tag'>第 "+(x.round||1)+" 轮</span>"+
                "</div>"+
            "</div>"+
            "<div class='memo-mini-actions'>"+
                "<button class='memo-mini-btn' data-lp-act='reroll-summary' data-id='"+esc(x.id)+"'>重抽</button>"+
                "<button class='memo-mini-btn' data-lp-act='edit-summary' data-id='"+esc(x.id)+"'>编辑</button>"+
                "<button class='memo-mini-btn danger' data-lp-act='delete-summary' data-id='"+esc(x.id)+"'>删除</button>"+
            "</div>"+
        "</div>"
    }).join('')
}

function longCards(s){
