    return arr.slice().reverse().map(function(x){
        return "<div class='long-card' data-lp-summary='"+esc(x.id)+"' data-lp-kind='long'>"+
            "<div class='long-range'>第 "+(x.round||1)+" 轮长期记忆 · 覆盖 "+(x.startL||0)+"L-"+(x.endL||0)+"L</div>"+
            "<div class='long-title'>"+esc(x.title||'长期记忆')+"</div>"+
            "<div class='long-preview' style='white-space:pre-wrap'>"+esc(clip(x.content||'',320))+"</div>"+
