    var title=x.title||(kind==='long'?'长期记忆':'阶段总结');
    var sub=kind==='long'?('覆盖 '+(x.startL||0)+'L-'+(x.endL||0)+'L'):((x.startL||0)+'L - '+(x.endL||0)+'L · 第 '+(x.round||1)+' 轮');
