var _renderTimer=null;
var _lastPage='';

async function _renderAll(){
    if(!app.core||!app.base)return;
    var c=core();
    var s=await c.load();
    if(c.countAssistant)await c.countAssistant();

    var el=q('#tvp-app');
    if(!el)return;

    var page=(s.ui&&s.ui.page)||'hero';

    var scrollEl=el.querySelector('.lp-main, .lp-scroll');
    var scrollTop=scrollEl?scrollEl.scrollTop:0;

    if(page==='summary'){
        el.innerHTML=summaryHtml(s)
    }else if(page==='tools'){
        el.innerHTML=toolsHtml(s)
    }else if(page==='memory'){
        el.innerHTML=sweetText(app.memoryPages&&app.memoryPages.renderMemory?app.memoryPages.renderMemory(s):placeholderHtml('甜蜜回忆','展示模块尚未加载'))
    }else if(page==='starmap'){
        el.innerHTML=sweetText(app.memoryPages&&app.memoryPages.renderStarmap?app.memoryPages.renderStarmap(s):placeholderHtml('记忆星图','星图模块尚未加载'))
    }else{
        el.innerHTML=heroHtml(s)
    }

    if(page!=='hero'||_lastPage!=='hero'){
        if(page==='hero'){
            var numEl=q('#lp-hero-num',el);
            var target=app._assistantCount||0;
            if(numEl&&target>0){
                numEl.textContent='0';
                requestAnimationFrame(function(){
                    requestAnimationFrame(function(){
                        animateNumber(numEl,target,800)
                    })
                })
            }
        }
    }
    _lastPage=page;

    if(scrollTop>0){
        var newScrollEl=el.querySelector('.lp-main, .lp-scroll');
        if(newScrollEl){
            newScrollEl.scrollTop=scrollTop
        }
    }

    if(app.memoryPages&&app.memoryPages.afterRender)app.memoryPages.afterRender(s)
}

function renderAll(){
    if(_renderTimer)clearTimeout(_renderTimer);
    _renderTimer=setTimeout(function(){_renderAll()},80)
}

function bindEditToolbar(){
    var root=q('#'+ROOT_ID);
    if(!root||root.getAttribute('data-edit-bound')==='1')return;
    root.setAttribute('data-edit-bound','1');

    root.addEventListener('click',function(e){
        var btn=e.target.closest('[data-edit-act]');
        if(!btn)return;

        e.preventDefault();
        e.stopPropagation();

        var action=btn.getAttribute('data-edit-act');
        var targetId=btn.getAttribute('data-target');
        var textarea=document.getElementById(targetId);

        if(!textarea)return;

        handleEditAction(action,textarea)
    })
}

async function handleEditAction(action,textarea){
    switch(action){
        case 'copy':
            textarea.select();
            document.execCommand('copy');
            base().toast&&base().toast('已复制到剪贴板');
            break;

        case 'paste':
            try{
                if(navigator.clipboard&&navigator.clipboard.readText){
                    var text=await navigator.clipboard.readText();
                    textarea.value=text;
                    base().toast&&base().toast('已粘贴');
                }else{
                    base().toast&&base().toast('请使用 Ctrl+V 粘贴');
                }
            }catch(err){
                base().toast&&base().toast('粘贴失败，请手动粘贴');
            }
            break;

        case 'clear':
            if(confirm('确定清空内容？')){
                textarea.value='';
            }
            break;
    }
}

async function act(a,n){
    var c=core();
    if(!c.load)return;
    var s=await c.load();

    if(a==='nav'){
        s.ui.page=n.getAttribute('data-lp-nav')||'hero';
        if(s.ui.page!=='memory'){s.ui.memoryView='list'}
        await c.save(s);
        return renderAll()
    }

    if(a==='tab'){
        s.ui.summaryTab=n.getAttribute('data-lp-tab')||'short';
        await c.save(s);
        return renderAll()
    }

    if(a==='start-current')return c.startFromCurrent();

    if(a==='run-summary')return c.runSummary();

    if(a==='scan-events')return c.scanEvents();

    if(a==='pause-scan')return c.pauseScan();

    if(a==='cancel-scan'){
        if(!confirm('确认取消当前任务？'))return;
        return c.cancelScan()
    }

    if(a==='continue-scan')return c.scanEvents();

    if(a==='summary')return detailOverlay(s,n.getAttribute('data-lp-summary'),n.getAttribute('data-lp-kind'));

    if(a==='help')return helpOverlay();

    if(a==='logs'){
        var b=n.querySelector?n.querySelector('.badge'):null;
        if(b)b.remove();
        await logsOverlay(s);
        return
    }

    if(a==='save-api')return c.saveApi(q('#lp-api-base').value,q('#lp-api-key').value,q('#lp-api-model').value);
    if(a==='test-api')return c.testApi();

    if(a==='save-settings'){
        return c.updateSettings({interval:q('#lp-interval').value,long_term_rounds:q('#lp-long-rounds').value})
    }

    if(a==='save-prompts'){
        return c.savePrompts({summary:q('#lp-prompt-summary').value,long_term:q('#lp-prompt-long').value,event:q('#lp-prompt-event').value})
    }
    if(a==='reset-prompts'){
        if(!confirm('确认恢复默认提示词？'))return;
        var d=c.DEFAULT_PROMPTS||{};
        return c.savePrompts({summary:d.summary||'',long_term:d.long_term||'',event:d.event||''})
    }

    if(a==='reroll-summary'){
        if(!confirm('确认重抽这条阶段总结？'))return;
        return c.rerollSummary(n.getAttribute('data-id'))
    }
    if(a==='edit-summary'){
        return editSummaryOverlay(s,n.getAttribute('data-id'))
    }
    if(a==='save-summary-edit'){
        return c.updateSummary(n.getAttribute('data-id'),{
            title:q('#lp-edit-summary-title').value,
            summary:q('#lp-edit-summary-body').value
        }).then(function(){base().closeOverlay&&base().closeOverlay()})
    }
    if(a==='delete-summary'){
        if(!confirm('确认删除这条阶段总结？'))return;
        return c.deleteSummary(n.getAttribute('data-id'))
    }

    if(a==='sync-memory')return c.syncMemory();

    if(a==='run-backfill'){
        if(!confirm('将从 1L 到启动锚点逐块生成总结，耗时较长。可随时暂停。确认？'))return;
        return c.runBackfill()
    }

    if(a==='export')return c.exportData();

    if(a==='clear'){
        if(confirm('确认清空全部数据？'))await c.clearAll();
        return renderAll()
    }

    if(app.memoryPages&&app.memoryPages.act){
        var handled=await app.memoryPages.act(a,n,s);
        if(handled)return renderAll()
    }
}

function bind(){
    var r=base().ensureRoot?base().ensureRoot():q('#'+ROOT_ID);
    if(!r)return;
    if(r.getAttribute('data-light-bound')==='1')return;
    r.setAttribute('data-light-bound','1');

    r.addEventListener('click',function(e){
        var n=e.target.closest?e.target.closest('[data-lp-nav],[data-lp-tab],[data-lp-act],[data-lp-summary],[data-lp-help],[data-lp-logs],[data-ms-act]'):null;
        if(!n)return;

        e.preventDefault();
        e.stopPropagation();

        var a=n.getAttribute('data-lp-act')||n.getAttribute('data-ms-act')||'';

        if(n.hasAttribute('data-lp-nav'))a='nav';
        else if(n.hasAttribute('data-lp-tab'))a='tab';
        else if(n.hasAttribute('data-lp-summary'))a='summary';
        else if(n.hasAttribute('data-lp-help'))a='help';
        else if(n.hasAttribute('data-lp-logs'))a='logs';

        act(a,n).catch(function(err){
            console.warn('[LightPages]',err);
            base().toast&&base().toast('操作失败：'+clip(err.message||'未知错误',40))
        })
    },true)
}

function mount(){
    ensureStyle();
    if(base().ensureRoot)base().ensureRoot();
    bind();
    bindEditToolbar();

    app.ui=app.ui||{};
    app.ui.renderAll=renderAll;
    if(base().open)app.ui.open=base().open;
    if(base().close)app.ui.close=base().close;
    if(base().toast)app.ui.toast=base().toast;

    renderAll()
}

mount()

}catch(e){console.warn('[LightPages fatal]',e)}
})();
